pub enum MessageView {
    GetRequest { key: AbstractKey },
    SetRequest { key: AbstractKey, value: Option<Seq<u8>> },
    Reply { key: AbstractKey, value: Option<Seq<u8>> },
    Redirect { key: AbstractKey, id: AbstractEndPoint },
    Shard { range: KeyRange<AbstractKey>, recipient: AbstractEndPoint },
    Delegate { range: KeyRange<AbstractKey>, h: Map<AbstractKey, Seq<u8>> },
}

impl View for Message {
    type V = MessageView;
    closed spec fn view(&self) -> MessageView {
        match self {
            Message::GetRequest { key } => MessageView::GetRequest { key: *key },
            Message::SetRequest { key, value } => MessageView::SetRequest { key: *key, value: value@ },
            Message::Reply { key, value } => MessageView::Reply { key: *key, value: value@ },
            Message::Redirect { key, id } => MessageView::Redirect { key: *key, id: *id },
            Message::Shard { range, recipient } => MessageView::Shard { range: *range, recipient: *recipient },
            Message::Delegate { range, h } => MessageView::Delegate { range: *range, h: h@ },
        }
    }
}

